sql.where:
r.del_flag = 0
AND r.name LIKE CONCAT('%', #{dto.name}, '%')
AND r.sn = #{dto.sn}
AND r.company_id = #{dto.companyId}
AND EXISTS (SELECT 1 FROM tbl_privilege_user_role ur LEFT JOIN tbl_privilege_user u ON u.id::text = ur.user_id WHERE ur.role_id = r.id AND ur.del_flag = 0 AND u.del_flag = 0 AND (u.code LIKE CONCAT('%', #{dto.keyword}, '%') OR u.username LIKE CONCAT('%', #{dto.keyword}, '%') OR u.real_name LIKE CONCAT('%', #{dto.keyword}, '%')))
